# DK VGS.  Varde - Grindsted
with detail = 2 {
    let vg = path("d2.dk.vgs");

    with railway = :first :pax :removed {
        with link = "line.dk.VGS" {
            track(vg[:var.yg, :var.yg + 9.5km]);
            line_label(:right:nw, vg[:var.yg + 9.5km] >> 0.5mt, "VGS");
            track(vg[:var.yg + 9.5km, :gri.yv - 7.1km]);
            line_label(:left:s, vg[:gri.yv - 7.1km] << 0.5mt, "VGS");
            track(vg[:gri.yv - 7.1km, :gri.yv]);
        }
    }
}


# DK VHT.  Valby - Høje Taastrup (S-tog)
with detail = 2 {
    let vh = path("d2.dk.kfa");

    with railway = :first :double :cat:dc15 :pax {
        with link = "line.dk.VHT" {
            with layer = -1 track(vh[:val.yf, :hvf.yv] >> 1md >> 1ms);
            track(vh[:hvf.yv, :hvf] >> 1md >> 1ms);
            track(vh[:hvf, :hoj - 6km] >> 1md >> 1ms);
            line_label(:right:s, vh[:hoj - 6km] >> 1md >> 1ms, "VHT");
            track(vh[:hoj - 6km, :hoj] >> 1md >> 1ms);
        }

        with link = "point.dk.Høje-Taastrup" {
            statdot(vh[:hoj] >> 1md >> 1ms);
            slabel(:left :cat:ac25, vh[:hoj] >> 1md >> 1ms + (1.5dt, -1dt),
                vbox(:right:bottom, "Høje", "Taastrup")
            );
        }
    }
}


# DK VKB.  Vigerslev - Kalvebod
with detail = 2 {
    let vk = path("d2.dk.vkb");

    with railway = :first :double :cat:ac25 :pax {
        with link = "line.dk.VKB" {
            with layer = -1 track(vk[:vig.yk, :kal.yv]);
        }
    }
}


# DK VLH.  København Syd - Hellerup
with detail = 2 {
    let vh = path("d2.dk.vlh");

    with railway = :first :double :cat:dc15 :pax {
        with link = "point.dk.København-Syd" {
            statdot(vh[:nel] >> 1md >> 1ms);
        }

        with link = "line.dk.VLH" {
            track(vh[:nel, :vig] >> 1ms >> 1md);
            track(:casing,
                    vh[:vig, :vig.yh] >> 1ms >> 1md
                ..  vh[:vig.xh + 1md, :ler]
            );
        }

        with link = "point.dk.Lersøen" {
            statdot(:nopax, vh[:ler]);
        }

        with link = "line.dk.VLH" {
            with layer = -1 track(vh[:ler, :ryp.yf]);
            track(vh[:ryp.yf, :ryp]);
            track(
                    vh[:ryp - 0.1dl, :ryp]
                ..  vh[:hel.yv, :hel.yv + 0.1dl] << 1md << 1ms
            );
        }
    }
}


# DK VLV.  Vemb - Lemvig
with detail = 2 {
    let vl = path("d2.dk.vlv");

    with railway = :first :pax {
        with link = "line.dk.VLV" {
            track(vl[:vem.yl, :vem.yl + 8.41km]);
            line_label(:left:e, vl[:vem.yl + 8.4km] << 0.5mt, "VLV");
            track(vl[:vem.yl + 8.39km, :lem.yt - 3.29km]);
            line_label(:right:nw, vl[:lem.yt - 3.3km] >> 0.5mt, "VLV");
            track(vl[:lem.yt - 3.31km, :lem.yt]);
        }

        with link = "point.dk.Lemvig", railway = :station {
            track(vl[:lem.yt, :lem]);
            statdot(vl[:lem]);
            slabel(:right, vl[:lem] + (1.5dt, 0.8dt), "Lemvig");
        }
    }
}


# DK VNT.  Varde - Nørre Nebel – Tarm
with detail = 2 {
    let vt = path("d2.dk.vnt");

    with railway = :first :pax {
        with link = "line.dk.VNT" {
            track(vt[:var.yn, :var.yn + 5.9km]);
            line_label(:right:s, vt[:var.yn + 5.9km] >> 0.5mt, "VNT");
            track(vt[:var.yn + 5.9km, :nor - 7.2km]);
            line_label(:right:w, vt[:nor - 7.2km] >> 0.5mt, "VNT");
            track(vt[:nor - 7.2km, :nor]);
        }

        with link = "point.dk.Nørre-Nebel" {
            track(:closed, vt[:nor, :nor.yn]);
            statdot(vt[:nor]);
            slabel(:right, vt[:nor] + (1.5dt, 0dt), "Nørre Nebel");
        }
    }

    with railway = :first :pax :removed {
        with link = "line.dk.VNT" {
            track(vt[:nor.yn, :tar.yn - 10km]);
            line_label(:left:e, vt[:tar.yn - 10km] << 0.5mt,
                (0dt, -0.5dt), "VNT"
            );
            track(vt[:tar.yn - 10km, :tar.yn]);
        }
    }
}


# DK VRS.  Vigerslev - Ringstedt
with detail = 2 {
    let vr = path("d2.dk.vrs");

    with railway = :first :double :cat:ac25 :pax {
        with link = "line.dk.VRS" {
            track(vr[:vig.yr, :vig.yr + 20km]);
            line_label(:right:se, vr[:vig.yr + 20km], "VRS");
            track(vr[:vig.yr + 20km, :kon]);
        }

        with link = "point.dk.Køge-Nord" {
            statdot(vr[:kon]);
            slabel(:right, vr[:kon] << 1md << 1ms + (1.5dt, 1.2dt),
                "Køge Nord"
            );
        }

        with link = "line.dk.VRS" {
            with layer = -1 track(:casing, vr[:kon, :kon + 9km]);
            line_label(:right:s, vr[:kon + 9km], (0.2dt, 0dt), "VRS");
            track(
                    vr[:kon + 9km, :kva.xk]
                ..  vr[:kva.yk, :rin] << 1md << 1ms
            );
        }
    }
}


# DK VVG.  Vejle Nord - Vandel - Grindsted
with detail = 2 {
    let vg = path("d2.dk.vvg");

    with railway = :first :pax :removed {
        with link = "line.dk.VVG" {
            track(vg[:ven, :ven + 10.81km]);
            line_label(:left:nw, vg[:ven + 10.8km] << 0.5mt, "VVG");
            track(vg[:ven + 10.79km, :van]);
        }

        with link = "point.dk.Vandel" {
            statdot(vg[:van]);
            slabel(:top, vg[:van] + (1dt, -0.8dt), "Vandel");
        }

        with link = "line.dk.VVG" {
            track(vg[:van, :gri.yh]);
            line_label(:right:s, vg[:van + 9km] >> 0.5mt, (0.5dt, 0dt), "VVG");
        }
    }
}

